1	type ScenarioResult = { premium?: number; payout?: number };
2	type ScenarioOutput = { results: ScenarioResult[] };
3	
4	type Item = { type: string; cursed?: boolean; enchantment?: number };
5	type Step = { op: string; items: Item[] };
6	type Customer = { yearsWithMHPCO?: number };
7	type Input = { customer?: Customer; steps: Step[] };
8	
9	const COMPONENT_PREMIUM = 33;
10	const HIGHLY_ENCHANTED_MIN = 5;
11	const LOYALTY_MIN_YEARS = 2;
12	
13	const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
14	  sword: 115,
15	  amulet: 71,
16	  staff: 93,
17	  potion: 49,
18	  rune: COMPONENT_PREMIUM,
19	  moonstone: COMPONENT_PREMIUM,
20	};
21	
22	const isHighlyEnchanted = (item: Item): boolean =>
23	  (item.enchantment ?? 0) >= HIGHLY_ENCHANTED_MIN;
24	
25	const hasLoyalty = (customer: Customer | undefined): boolean =>
26	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MIN_YEARS;
27	
28	const isAfterFirstStep = (stepIndex: number): boolean => stepIndex >= 1;
29	
30	const allItemsAreType = (step: Step, type: string): boolean =>
31	  step.items.every((i) => i.type === type);
32	
33	const isThreeRuneBlock = (step: Step): boolean =>
34	  step.items.length === 3 && allItemsAreType(step, "rune");
35	
36	const isTwoRunes = (step: Step): boolean =>
37	  step.items.length === 2 && allItemsAreType(step, "rune");
38	
39	export function runScenario(input: unknown): ScenarioOutput {
40	  const { customer, steps } = input as Input;
41	  const results = steps.map((step, stepIndex) => {
42	    const item = step.items[0];
43	    if (isThreeRuneBlock(step)) {
44	      return { premium: 71 };
45	    }
46	    if (isTwoRunes(step)) {
47	      return { premium: 60 };
48	    }
49	    if (item.cursed) {
50	      return { premium: 170 };
51	    }
52	    if (isHighlyEnchanted(item)) {
53	      return { premium: 148 };
54	    }
55	    if (hasLoyalty(customer)) {
56	      return { premium: 93 };
57	    }
58	    if (isAfterFirstStep(stepIndex)) {
59	      return { premium: 90 };
60	    }
61	    return { premium: PREMIUM_BY_ITEM_TYPE[item.type] };
62	  });
63	  return { results };
64	}
